import { getGrade } from '@/services/swagger/grade';
import { UploadOutlined } from '@ant-design/icons';
import { ProColumns, ProForm, ProFormText, ProTable } from '@ant-design/pro-components';
import { useModel } from '@umijs/max';
import { Button, Descriptions, DescriptionsProps, Divider, Drawer, message, Modal, Space, Upload, UploadProps } from 'antd';
import React, { useEffect } from 'react';
import GradeInflection from './inflection';
type GradeItem = {
    student_id: string,
    student_name:string,
    school_id:string,
    exam_id:string,
    examName:string,
    class_id:string,
    sum_:string,
    sumB:string,
    sumD:string,
    show:string,
    Dili: string,
    DiliB: string,DiliD: string,Huaxue: string,HuaxueB: string,HuaxueD: string,
    Lishi: string,LishiB: string,LishiD: string,Shengwu: string,ShengwuB: string,
    ShengwuD: string,Shuxue: string,ShuxueB: string,ShuxueD: string,Wuli: string,
    WuliB: string,WuliD: string,Yingyu: string,YingyuB: string,YingyuD: string,
    Yuwen: string,YuwenB: string,YuwenD: string,Zhengzhi: string,ZhengzhiB: string,ZhengzhiD: string,
}




const props: UploadProps = {
    name: 'file',
    action: '/api/upload/grade',
    onChange(info) {
        console.log('Upload event:', info);
        if (info.file.status !== 'uploading') {
            console.log(info.file, info.fileList);
        }
        if (info.file.status === 'done') {
            message.success(`${info.file.name} 成绩表上传成功！`);
        } else if (info.file.status === 'error') {
            message.error(`${info.file.name} 成绩表上传失败.`);
        }
    },
  };
const Grade: React.FC = () => { 
    const { initialState, } = useModel('@@initialState');
    const [open, setOpen] = React.useState(false);
    const [isModalOpen, setIsModalOpen] = React.useState(false);
    const [currentRow , setCurrentRow] = React.useState<GradeItem>();
    const columns:ProColumns<GradeItem>[] = [
        {
            title: '学校',
            dataIndex: 'school_id',
            hideInSearch:true,
            width: 48,

        },
        {
            title: '考试编号',
            dataIndex: 'exam_id',
            hideInSearch:false,
            width: 48,
        },
        {
            title: '班级编号',
            dataIndex: 'class_id',
            hideInSearch:false,
            width: 48,
        },
        {
            title: '学号',
            dataIndex: 'student_id',
            hideInSearch:false,
            width: 48,
            render: (text, record, index) => {
                
                return <a onClick={() => {
                    console.log(record, index,text)
                    // const display = {}
                    // for(let item in record) {
                    //     if (item !== null) {
                    //         display[item] = record[item]
                            
                    //     }
                    // }
                    // console.log(display)
                    setCurrentRow(record)
                    setOpen(true)
                }}>{text}</a>
            }
        },
        {
            title: '学生姓名',
            dataIndex: 'student_name',
            hideInSearch:true,
            width: 48,
        },
        {
            title: '总得分',
            dataIndex: 'sum_',
            hideInSearch:true,
            width: 48,
        },
        {
            title: '班次',
            dataIndex: 'sumB',
            hideInSearch:true,
            width: 48,
        },
        {
            title: '校次',
            dataIndex: 'sumD',
            hideInSearch:true,
            width: 48,
        },
        {
            title: '是否显示',
            dataIndex: 'show',
            hideInSearch:true,
            valueType: 'select',
            width:48,
            valueEnum: {
                true: {
                    text: '是',
                    status: 'true',
                },
                false: {
                    text: '否',
                    status: 'false',
                },
            },
        },
        {
            title: '操作',
            valueType: 'option',
            width: 48,
            render: (text, record, index) => [
                <a key="link" onClick={() => {
                    setIsModalOpen(true)
                }}>修改</a>,
                <a key="link2" onClick={() => {
                    console.log(record, index,text)
                    setCurrentRow(record)
                    setOpen(true)
                }}>删除</a>,
            ],
        }
        
    ]
    const items:DescriptionsProps['items'] = [
        // {key: 'student_id',label: '学号',children: currentRow?.student_id},
        // {key: 'student_name',label: '姓名',children: currentRow?.student_name},
        // {key: 'school_id',label: '学校id',children: currentRow?.school_id},
        // {key: 'exam_id',label: '考试id',children: currentRow?.exam_id},
        // {key: 'class_id',label: '班级id',children: currentRow?.class_id},
        {key: 'sum_',label: '总分',children: currentRow?.sum_},
        {key: 'sumB',label: '班次',children: currentRow?.sumB},
        {key: 'sumD',label: '校次',children: currentRow?.sumD},
        {key: 'show',label: '是否显示',children: currentRow?.show},
        {key: 'Dili',label: '地理',children: currentRow?.Dili},
        {key: 'DiliB',label: '地理班次',children: currentRow?.DiliB},
        {key: 'DiliD',label: '地理校次',children: currentRow?.DiliD},
        {key: 'Huaxue',label: '化学',children: currentRow?.Huaxue},
        {key: 'HuaxueB',label: '化学班次',children: currentRow?.HuaxueB},
        {key: 'HuaxueD',label: '化学校次',children: currentRow?.HuaxueD},
        {key: 'Lishi',label: '历史',children: currentRow?.Lishi},
        {key: 'LishiB',label: '历史班次',children: currentRow?.LishiB},
        {key: 'LishiD',label: '历史校次',children: currentRow?.LishiD},
        {key: 'Shengwu',label: '生物',children: currentRow?.Shengwu},
        {key: 'ShengwuB',label: '生物班次',children: currentRow?.ShengwuB},
        {key: 'ShengwuD',label: '生物校次',children: currentRow?.ShengwuD},
        {key: 'Shuxue',label: '数学',children: currentRow?.Shuxue},
        {key: 'ShuxueB',label: '数学班次',children: currentRow?.ShuxueB},
        {key: 'ShuxueD',label: '数学校次',children: currentRow?.ShuxueD},
        {key: 'Wuli',label: '物理',children: currentRow?.Wuli},
        {key: 'WuliB',label: '物理班次',children: currentRow?.WuliB},
        {key: 'WuliD',label: '物理校次',children: currentRow?.WuliD},
        {key: 'Yingyu',label: '英语',children: currentRow?.Yingyu},
        {key: 'YingyuB',label: '英语班次',children: currentRow?.YingyuB},
        {key: 'YingyuD',label: '英语校次',children: currentRow?.YingyuD},
        {key: 'Yuwen',label: '语文',children: currentRow?.Yuwen},
        {key: 'YuwenB',label: '语文班次',children: currentRow?.YuwenB},
        {key: 'YuwenD',label: '语文校次',children: currentRow?.YuwenD},
        {key: 'Zhengzhi',label: '政治',children: currentRow?.Zhengzhi},
        {key: 'ZhengzhiB',label: '政治班次',children: currentRow?.ZhengzhiB},
        {key: 'ZhengzhiD',label: '政治校次',children: currentRow?.ZhengzhiD},
    ]
    const DetailInfo =()=>{
        if (!currentRow) {
            console.log('currentRow is null')
            return <div>暂无信息</div>
        }else{
            let detail:DescriptionsProps['items'] = []
            for(let item in items) {
                if (items[item].children !== null) {
                    detail.push(items[item])
                }
            }
            return (
                <Descriptions column={3} title="详细信息" items={detail} />
            )
        }
    }
    useEffect(() => {
        console.log('currentUser changed:', initialState?.currentUser);
      }, [initialState?.currentUser]);
        return (
        <>
            <div  className="space-align-block">
                <Space align="baseline" size='large'>
                    <h3>导入成绩表</h3>
                    <Upload {...props}>
                        <Button icon={<UploadOutlined />}>点击上传</Button>
                    </Upload>
                </Space>
            </div>
            <Divider />
            <ProTable<GradeItem>
                columns={columns}
                request={async ( {pageSize, current},filter) => {
                    console.log(pageSize, current, filter)
                    const res = await getGrade({page: current,size: pageSize},filter);
                    return {
                        data: res.data,
                        total: res.total,
                        success: true
                    }
                }}
            />
            <Drawer
                closeIcon={false}
                onClose={() => setOpen(false)}
                open={open}
            >
            {currentRow && <DetailInfo />}
            </Drawer>
            <Modal
                title="修改成绩"
                open={isModalOpen}
                onOk={() => {
                    setIsModalOpen(false);
                }}
                onCancel={() => {
                    setIsModalOpen(false);
                }}
            >
                <ProForm<{
                    Yuwen: '语文',
                    YuwenD: '语文分次',
                    Shuxue: '数学',
                    ShuxueD: '数学分次',
                    Yingyu: '英语',
                    YingyuD: '英语分次',
                    Wuli: '物理',
                    WuliD: '物理分次',
                    Huaxue: '化学',
                    HuaxueD: '化学分次',
                    Zhengzhi: '政治',
                    ZhengzhiD: '政治分次',
                    Lishi: '历史',
                    LishiD: '历史分次',
                    Shengwu: '生物',
                    ShengwuD: '生物分次',
                    Dili: '地理',
                    DiliD: '地理分次',
                    YuwenB: '语文班次',
                    ShuxueB: '数学班次',
                    YingyuB: '英语班次',
                    WuliB: '物理班次',
                    HuaxueB: '化学班次',
                    ZhengzhiB: '政治班次',
                    LishiB: '历史班次',
                    ShengwuB: '生物班次',
                    DiliB: '地理班次',
                    sum_: '总分',
                    sumB: '总分班次',
                    sumD: '总分分次',
                    id: 'id',
                    student_id: '学生id',
                    school_id: '学校id',
                    exam_id: '考试id',
                    class_id: '考试班级'
                    }>
                    layout="horizontal"
                >
                    <ProFormText name="sum_" label="总分" width="xs"/>
                    <ProFormText name="Yuwen" label="语文" width="xs"/>
                    <ProFormText name="Shuxue" label="数学" width="xs"/>
                    <ProFormText name="Yingyu" label="英语" width="xs"/>
                    <ProFormText name="Wuli" label="物理" width="xs"/>
                    <ProFormText name="Huaxue" label="化学" width="xs"/>
                    <ProFormText name="Zhengzhi" label="政治" width="xs"/>
                    <ProFormText name="Lishi" label="历史" width="xs"/>
                    <ProFormText name="Shengwu" label="生物" width="xs"/>
                    <ProFormText name="Dili" label="地理" width="xs"/>
                    <ProFormText name="Yingyu" label="英语" width="xs"/>
                    <ProFormText name="Wuli" label="物理" width="xs"/>
                    
                    
                </ProForm>
            </Modal>
        </>
    )
};


export default Grade;

